defmodule YourAppWeb.ProductController do
  use YourAppWeb, :controller

  alias YourApp.Product

  def index(conn, params) do
    search = params[:search]

    query =
      from(p in Product)
      where: fragment("name LIKE ?", "%#{search}%")

    case Repo.chat(conn, query) do
